export default async function PostPage({ params }: Props) {
  const { slug } = await params;

  const post = generatedPosts.find((item) => item.slug === slug);

  if (!post) {
    notFound();
  }

  const htmlContent = markdownToHtml(post.content);

  return (
    <article style={{ padding: "20px", maxWidth: "800px", margin: "0 auto" }}>
      {post.image && (
        <Image
          src={post.image}
          alt={post.title}
          width={800}
          height={400}
          style={{
            borderRadius: "10px",
            marginBottom: "20px",
            width: "100%",
            height: "auto",
          }}
        />
      )}

      <h1 style={{ fontSize: "28px", marginBottom: "10px" }}>{post.title}</h1>

      {post.author && (
        <p style={{ color: "#444", marginBottom: "4px", fontWeight: "bold" }}>
          Por {post.author}
        </p>
      )}

      <p style={{ color: "#666", marginBottom: "20px" }}>{post.date}</p>

      <hr />

      <div
        className="post-content"
        dangerouslySetInnerHTML={{ __html: htmlContent }}
      />

      <style>{`
        .post-content p {
          line-height: 1.8;
          margin-bottom: 16px;
          color: #333;
        }

        .post-content h1,
        .post-content h2,
        .post-content h3 {
          margin: 28px 0 12px;
          color: #111;
        }

        .post-content h2 {
          font-size: 22px;
        }

        .post-content h3 {
          font-size: 18px;
        }

        .post-content ul {
          padding-left: 24px;
          margin-bottom: 16px;
        }

        .post-content li {
          margin-bottom: 6px;
          line-height: 1.7;
        }

        .post-content blockquote {
          border-left: 4px solid #2E7D32;
          padding: 8px 16px;
          margin: 16px 0;
          background: #f9f9f9;
          color: #444;
          font-style: italic;
          border-radius: 0 6px 6px 0;
        }

        .post-content hr {
          border: none;
          border-top: 1px solid #eee;
          margin: 24px 0;
        }

        .post-content strong {
          color: #111;
        }

        .post-content a {
          color: #2E7D32;
          text-decoration: underline;
        }
      `}</style>
    </article>
  );
}

